// // This module implements a 16-bit shift register with parallel load.
// On each clock cycle, the shift register shifts right when the shift signal is high.
// When the load signal is high, it loads the parallel input data in reverse order.
// The reset signal is active low asynchronous and resets the register to all ones.
module shift_register_with_parallel_load (
	input clk,
	input reset,
	input shift,
	input load,
	input [15:0] data_in,
	output reg [15:0] data_out);

	always @(posedge clk) begin
		if (reset) begin
			data_out <= 16'b0;
		end else if (load) begin
			data_out <= data_in;
		end else if (shift) begin
			data_out <= {data_out[14:0], 1'b0};
		end
	end

endmodule

